def radius_search(grid, i,j,char):
    radius_coordinates = [
        (i-1, j), (i-1, j+1), (i, j+1), (i+1, j+1),
        (i+1, j), (i+1, j-1), (i, j-1), (i-1, j-1) 
    ]
    matches = []
    for x,y in radius_coordinates:
        if 0 <= x < len(grid[0])  and  0 <= y < len(grid):
            if grid[x][y] == char: 
                matches.append((x,y,radius_coordinates.index((x,y))))
    return matches

total_count = 0

for i in range(len(data)):
    for j in range(len(data[0])):
        if data[i][j] == 'X':
            m_vals = radius_search(data, i, j, 'M')
            a_vals = []
            s_vals = []
            for a,b,c in m_vals:
                a_vals.extend([v for v in radius_search(data,a,b,'A') if v[-1] == c])

            for c,d,e in a_vals:
                s_vals.extend([v for v in radius_search(data,c,d,'S') if v[-1] == e])
                
            total_count += len(s_vals)

print(total_count)


def makes_xmas(grid, i,j):
    radius_coordinates = [
        (i-1, j+1), (i+1, j+1),
        (i+1, j-1), (i-1, j-1) 
    ]
    ne_se_sw_nw = ''
    for i in range(len(radius_coordinates)):
        x,y = radius_coordinates[i]
        if 0 <= x < len(grid[0])  and  0 <= y < len(grid):
            ne_se_sw_nw += grid[x][y]

    return len(ne_se_sw_nw) == 4 and ne_se_sw_nw in ['SSMM','SMMS','MSSM','MMSS']
            
            
    
ct = 0
for i in range(len(data)):
    for j in range(len(data[0])):
        if data[i][j] == 'A':
            if makes_xmas(data, i, j): ct += 1

print(ct)